mapper.insert:
insert into notice (title,content,wdate,pname,fname)
values
(#{title},#{content},now(),

	#{pname},#{fname}


	null, null

)

mapper.select:
select 
	nno,title,content,wdate,pname,fname
from notice where nno = #{ nno }

mapper.update:
update notice set title= #{title}, content = #{content}

,pname = #{pname},
fname = #{fname}

where nno = #{ nno }
